class BSTNode:
    def __init__(self, char):
        self.char = char
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = BSTNode(char)
        else:
            self._insert_recursive(self.root, char)

    def _insert_recursive(self, node, char):
        if char == node.char:
            return
        if char < node.char:
            if node.left is None:
                node.left = BSTNode(char)
            else:
                self._insert_recursive(node.left, char)
        else:
            if node.right is None:
                node.right = BSTNode(char)
            else:
                self._insert_recursive(node.right, char)

def process_sequence(sequence):
    tree = BinarySearchTree()
    def recursive_loop(index):
        if index >= len(sequence):
            return
        char = sequence[index].lower()
        if char.isalnum():
            tree.insert(char)
        recursive_loop(index + 1)
    recursive_loop(0)
    return tree

